/**
 * RFQ copy lineage via rfqItem_copied_from_id.
 * Copied on/by are shown only when stored on RFQItem (rfqItem_copied_on, rfqItem_copied_by).
 */

const DEFAULT_MAX_DEPTH = 50;

/**
 * @param {object|null} user - designflow.users row
 */
function formatUserDisplay(user) {
  if (!user) {
    return null;
  }
  const first = (user.name || '').trim();
  const last = (user.lastname || '').trim();
  const displayName =
    [first, last].filter(Boolean).join(' ') || user.email || 'Unknown';
  const initials =
    ((first.charAt(0) || '') + (last.charAt(0) || first.charAt(1) || '')).toUpperCase() ||
    '?';
  return {
    userId: user.id ?? null,
    displayName,
    initials: initials || '?',
    email: user.email || null,
  };
}

/**
 * Build one lineage row. Copied on/by only from RFQItem columns (no audit fallback).
 */
function buildLineageEntry(item, parentItem, copiedByUser) {
  const isCopy = !!item.rfqItem_copied_from_id;

  let copiedOn = null;
  let copiedBy = null;

  if (isCopy && item.rfqItem_copied_on) {
    copiedOn = new Date(item.rfqItem_copied_on).toISOString();
  }
  if (isCopy && item.rfqItem_copied_by && copiedByUser) {
    copiedBy = formatUserDisplay(copiedByUser);
  }

  const createdOn = item.rfqItem_created_date
    ? new Date(item.rfqItem_created_date).toISOString()
    : null;
  const modifiedOn = item.rfqItem_date_modified
    ? new Date(item.rfqItem_date_modified).toISOString()
    : null;

  return {
    rfqItemId: item.rfqItem_id,
    styleNumber: item.rfqItem_style_number || null,
    description: item.rfqItem_description || null,
    rfqGroupName: item.rfqGroupName || null,
    copiedFromId: parentItem ? parentItem.rfqItem_id : null,
    copiedFromStyleNumber: parentItem ? parentItem.rfqItem_style_number || null : null,
    copiedOn,
    copiedBy,
    createdOn,
    modifiedOn,
    isRoot: !isCopy,
  };
}

/**
 * Walk order is newest → oldest; return as-is (most recent first).
 */
function buildLineageFromWalkedItems(walkedItems) {
  return walkedItems.map(({ item, parentItem, copiedByUser }) =>
    buildLineageEntry(item, parentItem, copiedByUser)
  );
}

/**
 * @param {object} models - Sequelize models bag
 * @param {number} rfqItemId - starting RFQ (usually the row the user right-clicked)
 * @param {number} [maxDepth]
 */
async function fetchRfqLineage(models, rfqItemId, maxDepth = DEFAULT_MAX_DEPTH) {
  const walked = [];
  const seen = new Set();
  let currentId = rfqItemId;

  while (currentId != null && walked.length < maxDepth) {
    if (seen.has(currentId)) {
      break;
    }
    seen.add(currentId);

    const row = await models.RFQItem.findOne({
      where: { rfqItem_id: currentId },
      include: [
        {
          model: models.RFQGroup,
          as: 'RFQGroup',
          required: false,
          attributes: ['RFQGroup_id', 'RFQGroup_name'],
        },
      ],
    });

    if (!row) {
      break;
    }

    const data = row.dataValues || row;
    const parentId = data.rfqItem_copied_from_id;

    let parentItem = null;
    if (parentId) {
      const parentRow = await models.RFQItem.findOne({
        where: { rfqItem_id: parentId },
        attributes: ['rfqItem_id', 'rfqItem_style_number', 'rfqItem_description'],
      });
      if (parentRow) {
        parentItem = parentRow.dataValues || parentRow;
      }
    }

    let copiedByUser = null;
    if (data.rfqItem_copied_by) {
      copiedByUser = await models.users.findByPk(data.rfqItem_copied_by);
    }

    walked.push({
      item: {
        rfqItem_id: data.rfqItem_id,
        rfqItem_style_number: data.rfqItem_style_number,
        rfqItem_description: data.rfqItem_description,
        rfqItem_copied_from_id: data.rfqItem_copied_from_id,
        rfqItem_copied_on: data.rfqItem_copied_on,
        rfqItem_copied_by: data.rfqItem_copied_by,
        rfqItem_created_date: data.rfqItem_created_date,
        rfqItem_date_modified: data.rfqItem_date_modified,
        rfqGroupName: data.RFQGroup?.RFQGroup_name || null,
      },
      parentItem,
      copiedByUser: copiedByUser ? copiedByUser.dataValues || copiedByUser : null,
    });

    currentId = parentId;
  }

  const lineage = buildLineageFromWalkedItems(walked);
  const current =
    walked.length > 0
      ? {
          rfqItemId: walked[0].item.rfqItem_id,
          styleNumber: walked[0].item.rfqItem_style_number,
        }
      : null;

  return {
    current,
    lineage,
    depth: lineage.length,
    hasCopyChain: lineage.some((e) => e.copiedFromId != null),
  };
}

module.exports = {
  DEFAULT_MAX_DEPTH,
  formatUserDisplay,
  buildLineageEntry,
  buildLineageFromWalkedItems,
  fetchRfqLineage,
};

