import { Component, Inject, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { MAT_DIALOG_DATA, MatDialogModule, MatDialogRef } from '@angular/material/dialog';
import { MatIconModule } from '@angular/material/icon';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
import { MatTooltipModule } from '@angular/material/tooltip';
import { itemService } from '../../../helpers/services/main.service';

export interface RfqHistoryDialogData {
  rfqItemId: number;
  styleNumber?: string;
}

interface LineageEntry {
  rfqItemId: number;
  styleNumber: string | null;
  description: string | null;
  rfqGroupName: string | null;
  copiedFromId: number | null;
  copiedFromStyleNumber: string | null;
  copiedOn: string | null;
  createdOn: string | null;
  modifiedOn: string | null;
  copiedBy: {
    userId: number | null;
    displayName: string;
    initials: string;
    email: string | null;
  } | null;
  isRoot: boolean;
}

@Component({
  selector: 'app-rfq-history-dialog',
  templateUrl: './rfq-history-dialog.component.html',
  styleUrls: ['./rfq-history-dialog.component.scss'],
  imports: [
    CommonModule,
    MatDialogModule,
    MatIconModule,
    MatProgressSpinnerModule,
    MatTooltipModule,
  ],
})
export class RfqHistoryDialogComponent implements OnInit {
  isLoading = true;
  errorMessage: string | null = null;
  lineage: LineageEntry[] = [];
  hasCopyChain = false;
  currentStyleNumber: string | null = null;

  constructor(
    public dialogRef: MatDialogRef<RfqHistoryDialogComponent>,
    @Inject(MAT_DIALOG_DATA) public data: RfqHistoryDialogData,
    private itemService: itemService
  ) {}

  ngOnInit(): void {
    this.currentStyleNumber = this.data.styleNumber || null;
    this.itemService.getRfqItemHistory({ rfqItem_id: this.data.rfqItemId }).subscribe({
      next: (res: any) => {
        this.isLoading = false;
        if (res?.status === 200 && res.data) {
          this.lineage = res.data.lineage || [];
          this.hasCopyChain = res.data.hasCopyChain;
          if (res.data.current?.styleNumber) {
            this.currentStyleNumber = res.data.current.styleNumber;
          }
          if (this.lineage.length === 0) {
            this.lineage = [this.buildFallbackRow()];
          }
        } else {
          this.errorMessage = res?.message || 'Could not load RFQ history.';
        }
      },
      error: () => {
        this.isLoading = false;
        this.errorMessage = 'Could not load RFQ history.';
      },
    });
  }

  get currentRfqItemId(): number {
    return this.data.rfqItemId;
  }

  isCurrentRow(row: LineageEntry): boolean {
    return row.rfqItemId === this.currentRfqItemId;
  }

  private buildFallbackRow(): LineageEntry {
    return {
      rfqItemId: this.data.rfqItemId,
      styleNumber: this.currentStyleNumber || this.data.styleNumber || null,
      description: null,
      rfqGroupName: null,
      copiedFromId: null,
      copiedFromStyleNumber: null,
      copiedOn: null,
      createdOn: null,
      modifiedOn: null,
      copiedBy: null,
      isRoot: true,
    };
  }

  avatarTone(userId: number | null): string {
    if (userId == null) return 'tone-neutral';
    const tones = ['tone-a', 'tone-b', 'tone-c', 'tone-d'];
    return tones[userId % tones.length];
  }

  onClose(): void {
    this.dialogRef.close();
  }
}

