<div class="rfq-history-modal">
  <header class="modal-header">
    <div class="header-title">
      <mat-icon class="header-icon">account_tree</mat-icon>
      <div>
        <h3>RFQ copy history</h3>
        <p class="subtitle">
          @if (currentStyleNumber) {
            <span>{{ currentStyleNumber }}</span>
          }
          <span class="rfq-id">#{{ data.rfqItemId }}</span>
        </p>
      </div>
    </div>
    <button type="button" class="header-close-btn" aria-label="Close" (click)="onClose()">
      <mat-icon>close</mat-icon>
    </button>
  </header>

  <div class="modal-body">
    @if (isLoading) {
      <div class="state-block">
        <mat-spinner diameter="36"></mat-spinner>
        <p>Loading copy lineage…</p>
      </div>
    }

    @if (!isLoading && errorMessage) {
      <div class="state-block error">
        <mat-icon>error_outline</mat-icon>
        <p>{{ errorMessage }}</p>
      </div>
    }

    @if (!isLoading && !errorMessage && lineage.length > 0) {
      @if (hasCopyChain) {
        <p class="intro">
          Each step is an RFQ created from a previous one. Most recent first.
          Copied on and Copied by appear only when recorded on the RFQ.
        </p>
      }

      <div class="lineage-table-wrap">
        <table class="lineage-table">
          <thead>
            <tr>
              <th scope="col" class="col-step">Step</th>
              <th scope="col">Style number</th>
              <th scope="col">Copied from</th>
              <th scope="col">Copied on</th>
              <th scope="col">Copied by</th>
              <th scope="col">Created date</th>
              <th scope="col">Date modified</th>
              <th scope="col">RFQ group</th>
            </tr>
          </thead>
          <tbody>
            @for (row of lineage; track row.rfqItemId; let i = $index) {
              <tr [class.row-current]="isCurrentRow(row)">
                <td class="col-step">
                  <span class="step-badge" [class.step-current]="isCurrentRow(row)">{{ i + 1 }}</span>
                </td>
                <td>
                  <span class="style-primary">{{ row.styleNumber || '—' }}</span>
                  @if (isCurrentRow(row)) {
                    <span class="tag-current">Current</span>
                  }
                  @if (row.description) {
                    <span class="style-desc">{{ row.description }}</span>
                  }
                </td>
                <td>
                  @if (row.copiedFromStyleNumber) {
                    <span class="copy-link">
                      <mat-icon>subdirectory_arrow_right</mat-icon>
                      {{ row.copiedFromStyleNumber }}
                    </span>
                  } @else {
                    <span class="muted">—</span>
                  }
                </td>
                <td class="col-date">
                  @if (row.copiedOn) {
                    {{ row.copiedOn | date: 'MMM d, y' }}
                  } @else {
                    <span class="muted">—</span>
                  }
                </td>
                <td>
                  @if (row.copiedBy) {
                    <div
                      class="user-chip"
                      [matTooltip]="row.copiedBy.email || row.copiedBy.displayName"
                    >
                      <span class="user-avatar" [ngClass]="avatarTone(row.copiedBy.userId)">
                        {{ row.copiedBy.initials }}
                      </span>
                      <span class="user-name">{{ row.copiedBy.displayName }}</span>
                    </div>
                  } @else {
                    <span class="muted">—</span>
                  }
                </td>
                <td class="col-date">
                  @if (row.createdOn) {
                    {{ row.createdOn | date: 'MMM d, y' }}
                  } @else {
                    <span class="muted">—</span>
                  }
                </td>
                <td class="col-date">
                  @if (row.modifiedOn) {
                    {{ row.modifiedOn | date: 'MMM d, y' }}
                  } @else {
                    <span class="muted">—</span>
                  }
                </td>
                <td class="col-group">{{ row.rfqGroupName || '—' }}</td>
              </tr>
            }
          </tbody>
        </table>
      </div>
    }
