          if (creationLog) {
            this.createdBy = creationLog.username;
            this.createdOn = creationLog.actionDate;
          } else if (this.logs.length > 0) {
            const lastLog = this.logs[this.logs.length - 1];
            this.createdBy = lastLog.username;
            this.createdOn = lastLog.actionDate;
