          newValue = this.stepMappings[newValue] || newValue;
        }

        if (key === 'rfqItem_active') {
          oldValue = this.statusMappings[oldValue] || oldValue;
          newValue = this.statusMappings[newValue] || newValue;
        }

        if (key === 'req_status') {
          oldValue = this.reqStatusMappings[oldValue] || oldValue;
          newValue = this.reqStatusMappings[newValue] || newValue;
        }

        if (key === 'rfqItem_rfq_group') {
          oldValue = this.rfqGroupMappings[oldValue] || oldValue;
          newValue = this.rfqGroupMappings[newValue] || newValue;
        }

        const formattedOldValue = this.formatValue(oldValue);
        const formattedNewValue = this.formatValue(newValue);

        if (formattedOldValue !== formattedNewValue) {
          changes.push({
            key: this.fieldMappings[key] || key,
            oldValue: formattedOldValue,
            newValue: formattedNewValue
          });
        }
      });
      return changes;
    }

    if (!this.isObject(oldObj) && this.isObject(newObj)) {
      Object.keys(newObj).forEach(key => {
        let mappedNewValue: any = newObj[key];

        // Apply mappings when there is no old object (creation case)
        if (key === 'rfqItem_step') {
          mappedNewValue = this.stepMappings[mappedNewValue] || mappedNewValue;
