        }

        if (key === 'rfqItem_rfq_group') {
          mappedNewValue = this.rfqGroupMappings[mappedNewValue] || mappedNewValue;
        }

        const newValueFormatted = this.formatValue(mappedNewValue);
        if (newValueFormatted !== null && newValueFormatted !== undefined && newValueFormatted !== '') {
          changes.push({
            key: this.fieldMappings[key] || key,
            oldValue: 'N/A',
            newValue: newValueFormatted
          });
        }
      });
      return changes;
    }

    if (this.isObject(oldObj) && !this.isObject(newObj)) {
      Object.keys(oldObj).forEach(key => {
        changes.push({
          key: this.fieldMappings[key] || key,
          oldValue: this.formatValue(oldObj[key]),
          newValue: 'N/A'
        });
      });
      return changes;
    }

    if (oldObj !== newObj) {
      const key = log.element_id;
      let oldValue = oldObj;
      let newValue = newObj;
      if (key === 'rfqItem_step') {
        oldValue = this.stepMappings[oldValue] || oldValue;
        newValue = this.stepMappings[newValue] || newValue;
      }

      if (key === 'rfqItem_rfq_group') {
        oldValue = this.rfqGroupMappings[oldValue] || oldValue;
        newValue = this.rfqGroupMappings[newValue] || newValue;
      }
      return [{
        key: this.fieldMappings[key] || key,
        oldValue: this.formatValue(oldValue),
        newValue: this.formatValue(newValue)
      }];
    }

    return [];
  }

  isObject(value: any) {
    return typeof value === 'object' && value !== null && !Array.isArray(value);
  }

  formatValue(value: any): string {
    if (value === null || value === undefined) {
      return value;
    }
    if (typeof value === 'object') {
      if (value.title) return value.title;
      if (value.name) return value.name;
      if (value.RFQGroup_name) return value.RFQGroup_name;
      return 'Object';
    }
    const date = new Date(value);
    if (!isNaN(date.getTime()) && typeof value === 'string' && value.includes('-')) {
      return new Date(value).toLocaleDateString('en-US', {
        year: 'numeric',
        month: 'short',
        day: 'numeric',
      });
    }
    return String(value);
  }

