// Sourcing/admin flags a stale vendor quote for refresh. Sets requote_requested
// on the RFQVendor (leaving quote_date untouched so the "Quoted <date>" tooltip
// keeps showing the original date) and emails the factory to ask for a fresh price.
Customer.requestRequote = async (req, result) => {
  try {
    const token = req.headers.authorization;
    const userInfo = await getUserInfo(token);
    const allowedRoles = ['admin', 'sourcing_manager', 'production'];
    if (!userInfo || !allowedRoles.includes(userInfo.role)) {
      return result(null, { status: 'forbidden' });
    }

    const rfqVendor = await sql.RFQVendor.findOne({ where: { RFQVendor_id: req.body.quote_id } });
    if (!rfqVendor) {
      return result(null, { status: 'quote_not_found' });
    }

    // Re-requesting a price reactivates the item for the vendor: auto-unarchive and
    // clear the sticky opt-out so the 3-month cycle restarts once they answer.
    await rfqVendor.update(
      { requote_requested: true, RFQVendor_archived: false, RFQVendor_archive_optout: false },
      { ref_id: rfqVendor.RFQitem_id_fk }
    );

    // Resolve the priceCode (style number) for the email — prefer the client-sent
    // value, fall back to the RFQItem the quote belongs to.
    let priceCode = req.body.priceCode;
    if (!priceCode) {
      const rfqItem = await sql.RFQItem.findOne({ where: { rfqItem_id: rfqVendor.RFQitem_id_fk } });
      priceCode = rfqItem ? rfqItem.rfqItem_style_number : null;
    }
    // RFQVendor.vendor_id_fk stores Factory.id (see reqVendor), which is what
    // emailVendorsForFactory expects.
    if (priceCode && rfqVendor.vendor_id_fk) {
      await emailVendorsForFactory(rfqVendor.vendor_id_fk, priceCode);
    }

    return result(null, { status: 'success' });
  } catch (err) {
    return result(null, { status: 'error', error: err });
  }
}

// Vendor reconfirms the existing price is still valid: clears the re-quote flag
// and refreshes quote_date to today so the price reads as freshly confirmed.
Customer.keepPrice = async (req, result) => {
  try {
    const userInfo = await getUserInfo(req.headers.authorization);
    const rfqVendor = await sql.RFQVendor.findOne({ where: { RFQVendor_id: req.body.quote_id } });
    if (!rfqVendor) {
      return result(null, { status: 'quote_not_found' });
    }
    // A vendor may only reconfirm their own factory's quote (prevents quote_id enumeration).
    if (!vendorMayModifyQuote(userInfo, rfqVendor)) {
      return result(null, { status: 'forbidden' });
    }
    // Keeping the price refreshes quote_date to today, so the auto-archive cycle
    // restarts: clear archive + opt-out alongside the re-quote flag.
    await rfqVendor.update(
      {
        requote_requested: false,
        quote_date: new Date().toISOString(),
        RFQVendor_archived: false,
        RFQVendor_archive_optout: false,
      },
      { ref_id: rfqVendor.RFQitem_id_fk }
    );
    return result(null, { status: 'success' });
  } catch (err) {
    return result(null, { status: 'error', error: err });
  }
}

async function updateSTDVendorPrice(std_vendor_id_fk, price) {
  const stdVendor = await sql.StandardizedVendor.findOne({ where: { pKey: std_vendor_id_fk } });
  if (stdVendor) {
    await stdVendor.update({ price: price });
    const rfqVendor = await sql.RFQVendor.findOne({ where: { std_vendor_id_fk: std_vendor_id_fk } });
    if (rfqVendor) {
      await rfqVendor.update({ RFQVendor_amount: price });
      return true;
    }
  }
  return false;
}

Customer.archiveRFQItem = async (req, result) => {
  let data = req.body.data
  data = await utility.mapRFQItem(data)
  const user = await getUserInfo(req.headers.authorization)

  // For vendors, archive is PER-VENDOR — flip their own RFQVendor row, never the
  // global RFQItem.rfqItem_archive flag (which would hide the item from Sourcing and
  // other factories). 'archive' url means the click came from the archive view → restore.
  if (user && user.role === 'vendor') {
    let factoryId = user.factory_id
    if (!factoryId && user.email) {
      const v = await sql.vendor.findOne({ where: { vendor_email: user.email } })
      if (v) factoryId = v.factory_id_fk
    }
    if (!factoryId) return result(null, [0])
    const item = await sql.RFQItem.findOne({
      where: { rfqItem_style_number: data.rfqItem_style_number },
      attributes: ['rfqItem_id']
    })
    if (!item) return result(null, [0])
    // url=='archive' → the click came from the archive view → restore (un-archive).
    // A manual un-archive is sticky: set the opt-out so the lazy sweep won't re-archive
    // it on the next list load. A manual archive clears the opt-out.
    const unarchiving = req.body.url == 'archive'
    return sql.RFQVendor.update(
      {
        RFQVendor_archived: unarchiving ? false : true,
        RFQVendor_archive_optout: unarchiving ? true : false,
      },
      { where: { RFQitem_id_fk: item.rfqItem_id, vendor_id_fk: factoryId } }
    )
      .then(d => result(null, d))
      .catch(err => result(err, null))
  }

  // Internal roles keep the global RFQItem archive behavior.
  if (req.body.url == 'archive') {
    data.rfqItem_archive = null
  } else {
    data.rfqItem_archive = 1
  }
  await sql.RFQItem.update(data, {
    where: {
      rfqItem_style_number: data.rfqItem_style_number
    },
    individualHooks: true
  })
    .then(async (data) => {
      if (data) {
        result(null, data);
      }
    })
    .catch(err => {
      result(err, null);
    });
}

