Customer.reqVendor = async (req, result) => {
  const rfqItem_priceCode = req.body.rfqItem_priceCode;
  const targetId = req.body.id; // can be factory_id or vendor_id depending on caller

  try {
    // Try to resolve by factory first
    let vendors = [];
    const factory = await sql.Factory.findOne({ where: { id: targetId } });

    if (factory) {
      // Fetch ALL vendors for the factory regardless of vendor_status to support temporary invites
      vendors = await sql.vendor.findAll({ where: { factory_id_fk: factory.id } });
    } else {
      // Fallback: treat id as vendor_id
      const vendor = await sql.vendor.findOne({ where: { vendor_id: targetId } });
      if (vendor) vendors = [vendor];
    }

    if (!vendors || vendors.length === 0) {
      return result(null, { status: 'no_vendors_found' });
    }

    const rfqItem = await sql.RFQItem.findOne({ where: { rfqItem_style_number: rfqItem_priceCode } });
    if (!rfqItem) {
      return result(null, { status: 'rfq_item_not_found' });
    }

    // Ensure we only trigger one email per request even if multiple vendor rows exist
    let hasEmailed = false;
    for (let i = 0; i < vendors.length; i++) {
      const vendorRow = vendors[i];
      const vendor_info = vendorRow.dataValues;
      const resolvedFactoryId = vendor_info.factory_id_fk; // keep schema: RFQVendor.vendor_id_fk stores Factory.id

      const [item, created] = await sql.RFQVendor.findOrCreate({
        where: {
          RFQitem_id_fk: rfqItem.dataValues.rfqItem_id,
          vendor_id_fk: resolvedFactoryId
        },
        defaults: {
          RFQitem_id_fk: rfqItem.dataValues.rfqItem_id,
          vendor_id_fk: resolvedFactoryId,
          quote_date: new Date().toISOString(),
        }
      });

      if (created) {
        if (req.body.sendEmail === true && !hasEmailed) {
          await sendPricReqEmail(vendor_info, rfqItem_priceCode);
        }
      } else {
        const rfqVendor = await sql.RFQVendor.findOne({
          where: {
            RFQitem_id_fk: rfqItem.dataValues.rfqItem_id,
            vendor_id_fk: resolvedFactoryId
          }
        });
        if (rfqVendor) {
          const updateData = await rfqVendor.update({ quote_date: new Date().toISOString() });
          if (updateData && req.body.sendEmail === true && !hasEmailed) {
            await sendPricReqEmail(vendor_info, rfqItem_priceCode);
            hasEmailed = true;
          }
        }
      }
      hasEmailed = true;
    }

    return result(null, { status: 'success' });
  } catch (err) {
    return result(null, { status: 'error', error: err });
  }
}


// 🔹 Get Factory with Active Vendors and Active Factory
async function getFactoryWithVendors(factoryId) {
  const factories = await sql.Factory.findAll({
    logging: console.log,
    where: {
      id: factoryId,
      factory_status: 'Active' // Ensures factory itself is active
    },
    include: [{
      model: sql.vendor,
      as: 'vendors',
      where: {
        vendor_status: 'Active' // Ensures vendors are active
      },
      required: false
    }]
  });

  return factories[0]?.dataValues || null;
}

// 🔹 Handle Individual Vendor Assignment
async function handleVendorAssignment(vendor, rfqItem_priceCode, factoryId, sendEmail) {
  const vendor_info = vendor.dataValues;

  const rfqItem = await getRFQItem(rfqItem_priceCode);
  if (!rfqItem) return;

  const rfqItemId = rfqItem.rfqItem_id;

  const [item, created] = await sql.RFQVendor.findOrCreate({
    where: {
      RFQitem_id_fk: rfqItemId,
      vendor_id_fk: factoryId
    },
    defaults: {
      RFQitem_id_fk: rfqItemId,
      vendor_id_fk: factoryId,
      quote_date: new Date().toISOString(),
    }
  });

  if (created) {
    if (sendEmail) {
      await sendPricReqEmail(vendor_info, rfqItem_priceCode);
    }
  } else {
    await updateVendorQuoteDate(rfqItemId, factoryId, vendor_info, rfqItem_priceCode, sendEmail);
  }
}

// 🔹 Get RFQ Item
async function getRFQItem(priceCode) {
  return await sql.RFQItem.findOne({
    where: { rfqItem_style_number: priceCode }
  }).then(item => item?.dataValues || null);
}


// 🔹 Update Vendor Quote Date and Send Email if required
async function updateVendorQuoteDate(rfqItemId, factoryId, vendor_info, rfqItem_priceCode, sendEmail) {
  try {
    const rfqVendor = await sql.RFQVendor.findOne({
      where: {
        RFQitem_id_fk: rfqItemId,
        vendor_id_fk: factoryId
      }
    });

    if (rfqVendor) {
      const updateData = await rfqVendor.update({ quote_date: new Date().toISOString() });
      if (updateData && sendEmail) {
        await sendPricReqEmail(vendor_info, rfqItem_priceCode);
      }
    }
  } catch (err) {
    console.error('Error updating quote date:', err);
    throw err;
  }
}

function buildRFQEmailTemplate(name, itemUrl, allItemsUrl) {
  return `
    <p>Hi ${name},<br/><br/>
    You have a new request for quotation from Edge Home. You can see this request here
    <a href="${itemUrl}">Link</a>.<br/>
    Or see all your requests here <a href="${allItemsUrl}">Link</a>.<br/><br/>

    Please make sure to fill in your price AND fill in the carton dimensions for the casepack specified in the inquiry.
    Without carton dimensions we cannot quote the customer because we won’t have the freight cost.
    If you do not want to quote something, please click PASS. Do NOT just leave it empty.<br/><br/>

    Edge Home 送来一份报价请求，您可以从这里提取 <a href="${itemUrl}">链接</a>.<br/>
