const { Op } = require('sequelize');

const CACHE_TTL_MS = 5 * 60 * 1000;

const RFQ_LIST_ITEM_EXCLUDE_ATTRIBUTES = [
  'rfqItem_auditlog',
  'rfqItem_default_cbm',
  'rfqItem_gen_fob_netsell',
  'rfqItem_gen_whse_netsell',
  'rfqItem_gen_poe_netsell',
  'rfqItem_gen_mddp_netsell',
  'rfqItem_gen_ldp_margin',
  'rfqItem_cbm_per_piece',
  'rfqItem_quote_update',
  'rfqItem_price_per_cbm',
  'rfqItem_standardized_products',
];

const RFQ_VENDOR_LIST_ATTRIBUTES = [
  'RFQVendor_id',
  'RFQVendor_amount',
  'RFQVendor_cbm_pc',
  'RFQVendor_status',
  'RFQitem_id_fk',
  'RFQVendor_note',
  'carton_width',
  'carton_height',
  'carton_length',
  'req_status',
  'vendor_id_fk',
  'quote_date',
  'std_vendor_id_fk',
  'lead_time',
  'price_terms',
  'fob_country',
  'fob_port',
  'requote_requested',
  'RFQVendor_archived',
  'RFQVendor_archive_optout',
];

const FACTORY_LIST_ATTRIBUTES = [
  'id',
  'factory_name',
  'factory_nickname',
  'factory_status',
  'factory_access',
  'factory_country',
  'sort_order',
];

let merchGroupCache = { rows: null, expiresAt: 0 };
let whsePriceCache = { value: null, expiresAt: 0 };

function buildMerchGroupMap(merchGroupData) {
  const map = new Map();
  if (!merchGroupData) {
    return map;
  }
  for (const row of merchGroupData) {
    const values = row.dataValues || row;
    const mgId = values.mg_id;
    if (mgId != null && mgId !== '') {
      map.set(String(mgId), values);
    }
  }
  return map;
}

/** Resolve merch group id to grid cell value. Never embed the full merchGroup list in JSON. */
function resolveMerchGroupValue(merchGroupMap, id) {
  if (id == null || id === '') {
    return null;
  }
  const mg = merchGroupMap.get(String(id));
  if (mg) {
    const values = mg.dataValues || mg;
    return { title: values.mg_desc, mg_code: values.mg_code, id: values.mg_id };
  }
  return { data: id };
}

async function getCachedMerchGroup(sql) {
  const now = Date.now();
  if (merchGroupCache.rows && merchGroupCache.expiresAt > now) {
    return merchGroupCache.rows;
  }
  const rows = await sql.merchGroup.findAll({
    attributes: ['mg_id', 'mg_code', 'mg_desc'],
  });
  merchGroupCache = { rows, expiresAt: now + CACHE_TTL_MS };
  return rows;
}

async function getCachedWhsePrice(sql) {
  const now = Date.now();
  if (whsePriceCache.value != null && whsePriceCache.expiresAt > now) {
    return whsePriceCache.value;
  }
  const rows = await sql.RFQWhse.findAll({
    attributes: ['RFQWhse_price'],
    limit: 1,
  });
  const value = rows[0]?.dataValues?.RFQWhse_price ?? null;
  whsePriceCache = { value, expiresAt: now + CACHE_TTL_MS };
  return value;
}

function buildRfqListLookupIncludes(sql, rfqVendorsInclude) {
  return [
    rfqVendorsInclude,
    {
      model: sql.customers,
      as: 'customer',
      attributes: [
        'customers_id',
        'customers_name',
        'customers_code',
        'customers_dilution',
        'customers_logistic_load',
      ],
    },
    {
      model: sql.RFQItemStatus,
      as: 'RFQItemStatus',
      attributes: ['RFQItemStatus_id', 'RFQItemStatus_title'],
    },
    {
      model: sql.itemDepth,
      as: 'itemDepth',
      attributes: ['itemDepth_id', 'itemDepth_code', 'itemDepth_title'],
    },
    {
      model: sql.deliveryLocation,
      as: 'deliveryLocation',
      attributes: ['deliveryLocation_id', 'deliveryLocation_title'],
    },
    {
      model: sql.RFQGroup,
      as: 'RFQGroup',
      attributes: ['RFQGroup_id', 'RFQGroup_name'],
    },
    {
      model: sql.RFQStep,
      as: 'RFQStep',
      attributes: ['RFQStep_id', 'RFQStep_title'],
    },
    {
      model: sql.Factory,
      as: 'Factory',
      attributes: FACTORY_LIST_ATTRIBUTES,
    },
    {
      model: sql.RFQContainer,
      as: 'RFQContainer',
      attributes: ['RFQContainer_id', 'RFQContainer_price'],
    },
  ];
}

function buildRfqVendorsInclude(sql, user) {
  const include = {
    model: sql.RFQVendor,
    as: 'RFQVendors',
    required: false,
    attributes: RFQ_VENDOR_LIST_ATTRIBUTES,
    include: [{
      model: sql.Factory,
      as: 'Factory',
      required: false,
      attributes: FACTORY_LIST_ATTRIBUTES,
    }],
  };
  if (user.role === 'vendor') {
    const vendorFilterIds = [...new Set([user.vendor_id, user.factory_id].filter(id => id != null && id !== ''))];
    if (vendorFilterIds.length) {
      include.where = {
        vendor_id_fk: vendorFilterIds.length === 1 ? vendorFilterIds[0] : { [Op.or]: vendorFilterIds },
      };
    }
  }
  return include;
}

module.exports = {
  RFQ_LIST_ITEM_EXCLUDE_ATTRIBUTES,
  buildMerchGroupMap,
  resolveMerchGroupValue,
  buildRfqListLookupIncludes,
  buildRfqVendorsInclude,
  getCachedMerchGroup,
  getCachedWhsePrice,
};

