/**
 * Keeps the read-only "Date sent to factory" grid column (`Factory_updated` row field) in sync with `Step.factoriesStepUpdatedAt`
 * when the row enters @factories. Both reflect DB column `rfqItem_factories_step_at` (see remapRFQItem).
 */

export function isFactoriesStepValue(step: unknown): boolean {
  if (!step || typeof step !== 'object') {
    return false;
  }
  const s = step as {
    id?: number;
    title?: string;
    RFQStep_id?: number;
    RFQStep_title?: string;
  };
  const id = s.id ?? s.RFQStep_id;
  const title = s.title ?? s.RFQStep_title;
  return title === '@factories' || id === 3;
}

/**
 * Sets `rowData[factoryUpdatedField]` to an ISO timestamp when `rowData[stepField]` is @factories.
 * Prefers `step.factoriesStepUpdatedAt` when stamping the Date sent to factory column.
 */
export function stampFactoryUpdatedFromStep(
  rowData: Record<string, unknown>,
  stepField: string,
  factoryUpdatedField: string
): void {
  const step = rowData[stepField] as { factoriesStepUpdatedAt?: string } | undefined;
  if (!isFactoriesStepValue(step)) {
    return;
  }
  const fromStep =
    typeof step?.factoriesStepUpdatedAt === 'string' && step.factoriesStepUpdatedAt.length > 0
      ? step.factoriesStepUpdatedAt
      : new Date().toISOString();
  rowData[factoryUpdatedField] = fromStep;
}

