#!/usr/bin/env node
/**
 * Downloads the full USITC HTS Revision (JSON export) and produces a compact
 * lookup file at data/hts-rates.json used by helpers/hts-rates.js.
 *
 * Source endpoint:
 *   https://hts.usitc.gov/reststop/exportList?from=0&to=99999&format=JSON&styles=true
 *
 * Output shape (per HTS number, only rows with a non-empty `general` rate):
 *   { "3926.40.00": { d: "Statuettes and other ornamental articles", g: "5.3%" }, ... }
 *
 * Re-run when USITC publishes a new HTS revision (typically yearly).
 */

'use strict';

const fs   = require('fs');
const path = require('path');
const https = require('https');

const URL  = 'https://hts.usitc.gov/reststop/exportList?from=0&to=99999&format=JSON&styles=true';
const OUT  = path.join(__dirname, '..', 'data', 'hts-rates.json');

function fetchJson(url) {
  return new Promise((resolve, reject) => {
    https.get(url, res => {
      if (res.statusCode !== 200) {
        return reject(new Error(`HTTP ${res.statusCode}`));
      }
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString('utf8'))); }
        catch (e) { reject(e); }
      });
      res.on('error', reject);
    }).on('error', reject);
  });
}

(async () => {
  console.log('Fetching USITC HTS export…');
  const rows = await fetchJson(URL);
  console.log(`  ${rows.length} rows received`);

  const lookup = {};
  for (const r of rows) {
    if (!r.htsno || !r.general || !r.general.trim()) continue;
    lookup[r.htsno] = {
      d: (r.description || '').replace(/\s+/g, ' ').trim().slice(0, 120),
      g: r.general.trim(),
    };
  }

  fs.mkdirSync(path.dirname(OUT), { recursive: true });
  fs.writeFileSync(OUT, JSON.stringify(lookup));
  const size = (fs.statSync(OUT).size / 1024 / 1024).toFixed(2);
  console.log(`Wrote ${Object.keys(lookup).length} codes to ${OUT} (${size} MB)`);
})().catch(err => {
  console.error('Failed:', err.message);
  process.exit(1);
});

