  ) && row.recovered_quote_date);

  let updated = 0;
  await client.query('BEGIN');
  try {
    for (const row of eligible) {
      const result = await client.query(
        `
          UPDATE ${rfqVendor}
          SET "quote_date" = $1
          WHERE "RFQVendor_id" = $2
            AND "quote_date" IS NULL
        `,
        [row.recovered_quote_date, row.quote_id]
      );
      updated += result.rowCount;
    }
    await client.query('COMMIT');
  } catch (err) {
    await client.query('ROLLBACK');
    throw err;
  }
  return { eligible: eligible.length, updated };
}

function summarize(rows) {
  return rows.reduce((acc, row) => {
    acc[row.status] = (acc[row.status] || 0) + 1;
    return acc;
  }, { exact: 0, approximate: 0, unrecoverable: 0 });
}

async function main() {
  const schema = process.env.SCHEMA || null;
  const client = newClient();
  await client.connect();
  try {
    const candidates = await fetchCandidates(client, schema);
    const rfqItemIds = [...new Set(candidates.map(row => Number(row.rfqItemId)).filter(Number.isFinite))];
    const auditRows = await fetchAuditRows(client, schema, rfqItemIds);
    const auditByRfqItem = groupAuditRowsByRfqItem(auditRows);
    const report = candidates.map(candidate => {
      const rows = auditByRfqItem.get(Number(candidate.rfqItemId)) || [];
      return toReportRow(candidate, findPriceReceivedEvent(candidate, rows));
    });

    const summary = summarize(report);
    const payload = {
      mode: apply ? 'apply' : 'dry-run',
      schema: schema || 'default search_path',
      candidates: candidates.length,
      auditRows: auditRows.length,
      summary,
    };

    if (apply) {
      payload.apply = await applyBackfill(client, schema, report);
    }

    if (outFile) {
      fs.writeFileSync(outFile, toCsv(report));
      payload.reportFile = outFile;
    }

    if (jsonOutput) {
      console.log(JSON.stringify({ ...payload, report }, null, 2));
    } else {
      console.log(`RFQ quote-date backfill ${payload.mode}`);
      console.log(`Schema: ${payload.schema}`);
      console.log(`Priced quote rows missing quote_date: ${payload.candidates}`);
      console.log(`Audit rows scanned: ${payload.auditRows}`);
      console.log(`Exact recoveries: ${summary.exact}`);
      console.log(`Approximate fallbacks: ${summary.approximate}`);
      console.log(`Unrecoverable: ${summary.unrecoverable}`);
      if (payload.apply) {
        console.log(`Eligible rows: ${payload.apply.eligible}`);
        console.log(`Rows updated: ${payload.apply.updated}`);
      }
      if (payload.reportFile) {
        console.log(`CSV report: ${payload.reportFile}`);
      }
      console.log('');
      console.log('Sample rows:');
      for (const row of report.slice(0, 10)) {
        console.log(JSON.stringify(row));
      }
      if (!apply) {
        console.log('');
        console.log('Dry-run only. Re-run with --apply to update exact recoveries.');
      }
    }
  } finally {
    await client.end();
  }
}

main().catch(err => {
  console.error(err.stack || err.message);
  process.exit(1);
});

