'use strict';

function parseAuditJson(value) {
  if (!value || typeof value !== 'string') {
    return null;
  }
  try {
    return JSON.parse(value);
  } catch (_err) {
    return null;
  }
}

function normalizePrice(value) {
  if (value == null) {
    return null;
  }
  const text = String(value).trim();
  if (!text) {
    return null;
  }
  const numeric = Number(text.replace(/[$,\s]/g, ''));
  if (Number.isFinite(numeric)) {
    return String(numeric);
  }
  return text;
}

function hasPrice(value) {
  return normalizePrice(value) != null;
}

function pricesDiffer(a, b) {
  return normalizePrice(a) !== normalizePrice(b);
}

function getQuoteIdFromAuditObject(obj) {
  const id = obj?.RFQVendor_id;
  if (id == null || id === '') {
    return null;
  }
  const parsed = Number(id);
  return Number.isFinite(parsed) ? parsed : null;
}

function dateOnly(value) {
  if (!value) {
    return null;
  }
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) {
    return null;
  }
  return date.toISOString().slice(0, 10);
}

function auditRowMatchesQuote(log, quoteId) {
  const oldObj = parseAuditJson(log.oldValue);
  const newObj = parseAuditJson(log.newValue);
  const oldQuoteId = getQuoteIdFromAuditObject(oldObj);
  const newQuoteId = getQuoteIdFromAuditObject(newObj);
  return {
    matches: oldQuoteId === quoteId || newQuoteId === quoteId,
    oldObj,
    newObj,
  };
}

function findPriceReceivedEvent(candidate, auditRows) {
  const quoteId = Number(candidate.quoteId);
  const sortedRows = [...(auditRows || [])].sort((a, b) => {
    const aTime = new Date(a.actionDate || 0).getTime();
    const bTime = new Date(b.actionDate || 0).getTime();
    if (aTime !== bTime) {
      return aTime - bTime;
    }
    return Number(a.id || 0) - Number(b.id || 0);
  });

  let parseErrors = 0;
  let quoteScopedRows = 0;
  for (const log of sortedRows) {
    const matched = auditRowMatchesQuote(log, quoteId);
    if (!matched.oldObj && !matched.newObj && (log.oldValue || log.newValue)) {
      parseErrors += 1;
      continue;
    }
    if (!matched.matches) {
      continue;
    }

    quoteScopedRows += 1;
    const oldPrice = matched.oldObj?.RFQVendor_amount;
    const newPrice = matched.newObj?.RFQVendor_amount;
    const newHasPrice = hasPrice(newPrice);
    const changedToPrice = newHasPrice && (!hasPrice(oldPrice) || pricesDiffer(oldPrice, newPrice));

    if (changedToPrice) {
      return {
        status: 'exact',
        quoteDate: dateOnly(log.actionDate),
        actionDate: log.actionDate,
        auditLogId: log.id,
        username: log.username || null,
        userId: log.user_id_fk ?? null,
        oldPrice: oldPrice ?? null,
        newPrice: newPrice ?? null,
        quoteScopedRows,
        parseErrors,
        reason: hasPrice(oldPrice) ? 'price_changed' : 'price_first_populated',
      };
    }
  }

  if (candidate.factorySentDate) {
    return {
      status: 'approximate',
      quoteDate: dateOnly(candidate.factorySentDate),
      actionDate: candidate.factorySentDate,
      auditLogId: null,
      username: null,
      userId: null,
      oldPrice: null,
      newPrice: candidate.price ?? null,
      quoteScopedRows,
      parseErrors,
      reason: 'no_price_audit_found_using_factory_sent_date',
    };
  }

  return {
    status: 'unrecoverable',
    quoteDate: null,
    actionDate: null,
    auditLogId: null,
    username: null,
    userId: null,
    oldPrice: null,
    newPrice: candidate.price ?? null,
    quoteScopedRows,
    parseErrors,
    reason: quoteScopedRows > 0 ? 'quote_audit_rows_without_price_change' : 'no_quote_audit_rows',
  };
}

module.exports = {
  auditRowMatchesQuote,
  dateOnly,
  findPriceReceivedEvent,
  hasPrice,
  normalizePrice,
  parseAuditJson,
  pricesDiffer,
};

