+function resolveQuoteDateForPriceUpdate(rfqVendor, incomingPrice, requestedQuoteDate) {
+  const incoming = normalizePrice(incomingPrice);
+  if (!incoming) {
+    return requestedQuoteDate || null;
+  }
+
+  const existing = normalizePrice(rfqVendor?.RFQVendor_amount);
+  const priceChanged = existing !== incoming;
+  const missingQuoteDate = !rfqVendor?.quote_date;
+  const answeringRequote = rfqVendor?.requote_requested === true;
+
+  if (priceChanged || missingQuoteDate || answeringRequote) {
+    return new Date().toISOString().slice(0, 10);
+  }
+
+  return requestedQuoteDate || rfqVendor.quote_date || null;
+}
